SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_chg_accno ON sc_mem_m_chg_accno CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_chg_accno() RETURNS trigger AS $BODY$
BEGIN

    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
      select max(seq_no) into STRICT NEW.seq_no
      from sc_mem_m_chg_accno
      where ( acc_type  = NEW.acc_type)
      --and membership_no = :new.membership_no 
;
      NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
    end if;


  if coalesce(trim(both NEW.entry_id)::text, '') = '' then NEW.entry_id := pka_com_function.fp_login_id;end if;
  if coalesce(trim(both NEW.entry_date)::text, '') = '' then NEW.entry_date := statement_timestamp();end if;

  if coalesce(trim(both NEW.app_status)::text, '') = '' then NEW.app_status := '2';end if;


    --Niorn 2024-02-21 TGE ให้โอนเฉพาะ กรุงไทย 10 หลัก 
    if len(trim(both NEW.accno_new))<> 10  then
        CALL spa_dberror('T22:ทะเบียน '||NEW.membership_no||' เลขบัญชีไม่เท่ากับ 10 หลัก');
    end if;

    if IS_NUMBER(NEW.accno_new)= 0 then
        CALL spa_dberror('T26:ทะเบียน '||NEW.membership_no||' เลขบัญชีรูปแบบไม่ถูกต้อง');
    end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
