CREATE TRIGGER tbiu_sc_mem_m_chg_accno
	BEFORE INSERT OR UPDATE ON sc_mem_m_chg_accno FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_mem_m_chg_accno();

